sql:
SELECT COUNT(*) AS registration_payments_count
FROM payment
WHERE payment_type = 'Registration';

SELECT program_description
FROM conference_program
WHERE program_id = 1;

SELECT comments
FROM feedback
WHERE rating = (SELECT MAX(rating) FROM feedback);

SELECT SUM(CAST(amount AS REAL)) AS total_sponsorship_amount
FROM payment
WHERE payment_type = 'Sponsorship';

SELECT AVG(rating) AS overall_average_rating
FROM feedback
WHERE rating != 1;

SELECT COUNT(*) AS number_of_presentations
FROM presentation_schedule
WHERE presentation_date = '2022-06-02';

SELECT presenter_name, presenter_affiliation
FROM program_presenters
WHERE program_id = 1;

SELECT full_name
FROM attendees
WHERE attendee_id IN (
    SELECT attendee_id
    FROM feedback
);
